"""
Walks lm_eval/tasks/**/*.yaml, extracts task/dataset_path/dataset_name,
and writes docs/dataset-mapping.md with a Markdown table.
"""

import logging
import yaml
from pathlib import Path

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Allow !function tags used in some task YAMLs to parse without error
yaml.add_multi_constructor("!function", lambda loader, tag, node: None, Loader=yaml.SafeLoader)

TASKS_DIR = Path("lm_eval/tasks")
OUTPUT_FILE = Path("docs/dataset-mapping.md")

rows = []

for yaml_file in sorted(TASKS_DIR.rglob("*.yaml")):
    try:
        with open(yaml_file, encoding="utf-8") as f:
            data = yaml.safe_load(f)
    except yaml.YAMLError as e:
        logger.error("Failed to parse %s: %s", yaml_file, e)
        continue
    except OSError as e:
        logger.error("Failed to read %s: %s", yaml_file, e)
        continue

    if not isinstance(data, dict):
        continue

    dataset_path = data.get("dataset_path")
    if not dataset_path or not isinstance(dataset_path, str):
        continue

    task = data.get("task", "")
    name = data.get("dataset_name") or ""
    if name and not isinstance(name, str):
        continue
    if isinstance(task, list):
        for t in task:
            if isinstance(t, str) and t.strip():
                rows.append((t, dataset_path, name))
    else:
        if isinstance(task, str) and task.strip():
            rows.append((task, dataset_path, name))

rows.sort(key=lambda r: r[0])

OUTPUT_FILE.parent.mkdir(parents=True, exist_ok=True)

with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
    f.write("# Benchmark Dataset Mapping\n\n")
    f.write(
        "This file is auto-generated by `.github/scripts/generate_dataset_table.py`.\n"
        "Do not edit manually — re-run the script instead.\n\n"
    )
    f.write(
        "Use the **HuggingFace Dataset Path** and **Subset** columns to pre-download\n"
        "datasets for air-gapped evaluation jobs.\n\n"
    )
    f.write(
        "> **Subset column**: If the value is `-`, the benchmark uses the full dataset with no subset.\n"
        "> Download examples:\n"
        "> ```python\n"
        "> from datasets import load_dataset\n"
        "> load_dataset(\"skg/toxigen-data\", \"annotated\")  # with subset\n"
        "> load_dataset(\"allenai/ai2_arc\")                 # no subset (-)\n"
        "> ```\n\n"
    )
    f.write("| Benchmark | HuggingFace Dataset Path | Subset |\n")
    f.write("|-----------|--------------------------|--------|\n")
    for task, path, name in rows:
        subset = f"`{name}`" if name else "-"
        f.write(f"| `{task}` | `{path}` | {subset} |\n")

logger.info("Written %d benchmarks to %s", len(rows), OUTPUT_FILE)
